const items = $input.all();
let results = [];

items.forEach(item => {
    let rawData = JSON.parse(item.json.data);

    rawData.forEach(entry => {
        let beneficiario = entry.Beneficiario;
        let resumoFinanceiro = entry.ResumoFinanceiro;
        let dadosBancarios = entry.DadosBancarios;
        let rmc = entry.Rmc;
        let rcc = entry.RCC;
        let associacao = entry.Associacao;
        let emprestimos = entry.Emprestimos;

        results.push({
            json: {
                Nome: beneficiario.Nome,
                CPF: beneficiario.CPF,
                DataNascimento: beneficiario.DataNascimento,
                Beneficio: beneficiario.Beneficio,
                Situacao: beneficiario.Situacao,
                NomeMae: beneficiario.NomeMae,
                Endereco: beneficiario.Endereco,
                Cidade: beneficiario.Cidade,
                CEP: beneficiario.CEP,
                UF: beneficiario.UF,
                ValorBeneficio: resumoFinanceiro.ValorBeneficio,
                BaseCalculo: resumoFinanceiro.BaseCalculo,
                MargemDisponivelEmprestimo: resumoFinanceiro.MargemDisponivelEmprestimo,
                TotalEmprestimos: resumoFinanceiro.TotalEmprestimos,
                Banco: dadosBancarios.Banco,
                Agencia: dadosBancarios.Agencia,
                ContaPagto: dadosBancarios.ContaPagto,
                MeioPagamento: dadosBancarios.MeioPagamento,
                RMC_Contrato: rmc?.Contrato || null,
                RMC_Banco: rmc?.NomeBanco || null,
                RMC_Valor: rmc?.Valor || null,
                RMC_ValorParcela: rmc?.ValorParcela || null,
                RCC_Contrato: rcc?.Contrato || null,
                RCC_Banco: rcc?.NomeBanco || null,
                RCC_Valor: rcc?.Valor || null,
                RCC_ValorParcela: rcc?.ValorParcela || null,
                Associacao_Taxa: associacao?.TaxaAssociativa || null,
                Associacao_Parcela: associacao?.Parcela || null,
                Emprestimos: emprestimos.map(e => ({
                    Banco: e.Banco,
                    NomeBanco: e.NomeBanco,
                    ValorParcela: e.ValorParcela,
                    Quitacao: e.Quitacao,
                    Prazo: e.Prazo,
                    Taxa: e.Taxa,
                    ParcelasRestantes: e.ParcelasRestantes,
                    Contrato: e.Contrato,
                    ValorEmprestimo: e.ValorEmprestimo,
                    DataAverbacao: e.DataAverbacao,
                    InicioDesconto: e.InicioDesconto,
                    FinalDesconto: e.FinalDesconto,
                }))
            }
        });
    });
});

return results;

const allDataNovaEra = $("Nova era Retenção").all();

const bmg = allDataNovaEra.filter((novaEra) => novaEra.json.Rmc.Banco == "318" || novaEra.json.RCC.Banco == "318")

const happy = allDataNovaEra.filter((novaEra) => novaEra.json.Rmc.Banco == "329" || novaEra.json.RCC.Banco == "329")

if (bmg.length >= 1) {
  return {
    "bank_name":"bmg", 
    "info": bmg
  };
} else if (happy.length >= 1) {
  return {
    "bank":"happy",
    "info": happy
  };
} else {
  return {"bank": "other"};
}

